import{c as t,Q as e,j as n,m as s}from"./chunks/framework.CQqJojvj.js";const h=JSON.parse('{"title":"17 - AI 大模型","description":"","frontmatter":{},"headers":[],"relativePath":"bagu/17-ai-llm.md","filePath":"bagu/17-ai-llm.md","lastUpdated":null}'),l={name:"bagu/17-ai-llm.md"};function i(r,a,o,p,d,c){return e(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="_17-ai-大模型" tabindex="-1">17 - AI 大模型 <a class="header-anchor" href="#_17-ai-大模型" aria-label="Permalink to &quot;17 - AI 大模型&quot;">​</a></h1><blockquote><p>AI 大模型是当前技术热点。面试中常问 RAG、幻觉、Function Calling、MCP 等概念，以及 AI 工具的实际使用经验。</p></blockquote><hr><h2 id="_1-如何理解大模型" tabindex="-1">1. 如何理解大模型？ <a class="header-anchor" href="#_1-如何理解大模型" aria-label="Permalink to &quot;1. 如何理解大模型？&quot;">​</a></h2><p>大模型（LLM, Large Language Model）是通过海量文本数据训练的深度学习模型。核心特征是：</p><ul><li><strong>规模巨大</strong> — 参数量从数十亿到数千亿不等</li><li><strong>涌现能力</strong> — 当模型规模超过某个临界值，会突然展现出训练时未显式教过的能力（如推理、翻译、编程）</li><li><strong>上下文学习</strong> — 通过 Prompt 中的示例就能完成新任务，无需微调（In-Context Learning）</li><li><strong>思维链</strong> — 在 Prompt 中加上 &quot;Let&#39;s think step by step&quot;，模型推理能力显著提升</li></ul><p><strong>GPT 训练流程：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pre-training（海量数据预训练，学习通用知识）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>SFT（有监督微调，学习遵循指令）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>RLHF（基于人类反馈的强化学习，对齐人类偏好）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="_2-大模型的幻觉-hallucination" tabindex="-1">2. 大模型的幻觉（Hallucination） <a class="header-anchor" href="#_2-大模型的幻觉-hallucination" aria-label="Permalink to &quot;2. 大模型的幻觉（Hallucination）&quot;">​</a></h2><p><strong>定义：</strong> 模型生成的内容看上去合理但与事实不符。</p><p><strong>原因：</strong></p><ol><li>训练数据不完整或包含错误信息</li><li>模型只学过训练数据中存在的知识</li><li>生成方式是逐 token 概率采样，没有真正的&quot;事实核查&quot;机制</li></ol><p><strong>缓解方法：</strong></p><ol><li><strong>RAG（检索增强生成）</strong> — 先检索相关文档，再基于文档生成回答</li><li><strong>限制回答范围</strong> — Prompt 中明确 &quot;如果不知道请说不知道&quot;</li><li><strong>结构化输出</strong> — 要求输出特定格式，减少自由发挥空间</li><li><strong>多轮验证</strong> — 生成后让模型自我检查</li></ol><hr><h2 id="_3-rag-检索增强生成" tabindex="-1">3. RAG（检索增强生成） <a class="header-anchor" href="#_3-rag-检索增强生成" aria-label="Permalink to &quot;3. RAG（检索增强生成）&quot;">​</a></h2><h3 id="核心流程" tabindex="-1">核心流程 <a class="header-anchor" href="#核心流程" aria-label="Permalink to &quot;核心流程&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户提问 → Query 向量化 → 向量相似度检索 → 召回相关文档</span></span>
<span class="line"><span>→ 拼接 Prompt（问题 + 召回文档）→ LLM 生成 → 返回答案</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="关键技术点" tabindex="-1">关键技术点 <a class="header-anchor" href="#关键技术点" aria-label="Permalink to &quot;关键技术点&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">环节</th><th style="text-align:left;">关键点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>文档切割</strong></td><td style="text-align:left;">合适的分块大小（500-1000 tokens），重叠保留上下文连贯性</td></tr><tr><td style="text-align:left;"><strong>向量化模型</strong></td><td style="text-align:left;">text-embedding-3, bge-large-zh 等</td></tr><tr><td style="text-align:left;"><strong>向量数据库</strong></td><td style="text-align:left;">Milvus / Pinecone / pgvector / Weaviate</td></tr><tr><td style="text-align:left;"><strong>检索优化</strong></td><td style="text-align:left;">动态 TopK、相似度阈值、Query Rewrite、混合检索（向量 + 关键词）</td></tr><tr><td style="text-align:left;"><strong>重排序（Rerank）</strong></td><td style="text-align:left;">检索后用 Cross-Encoder 对结果重新排序</td></tr></tbody></table><h3 id="rag-的优势" tabindex="-1">RAG 的优势 <a class="header-anchor" href="#rag-的优势" aria-label="Permalink to &quot;RAG 的优势&quot;">​</a></h3><ul><li>回答基于真实文档，减少幻觉</li><li>知识可动态更新（不重新训练模型）</li><li>可溯源（可展示引用的文档段落）</li></ul><p>详细 RAG 项目实现见 → <a href="/internship-prep-2026/projects/rag-project.html">RAG AI面试助手项目笔记</a></p><hr><h2 id="_4-function-calling-mcp" tabindex="-1">4. Function Calling &amp; MCP <a class="header-anchor" href="#_4-function-calling-mcp" aria-label="Permalink to &quot;4. Function Calling &amp; MCP&quot;">​</a></h2><h3 id="function-calling" tabindex="-1">Function Calling <a class="header-anchor" href="#function-calling" aria-label="Permalink to &quot;Function Calling&quot;">​</a></h3><p>模型不直接执行函数，而是输出结构化的函数调用请求（函数名 + 参数 JSON），应用代码解析后执行并返回结果给模型。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户: &quot;北京今天天气怎么样？&quot;</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>模型输出: { &quot;function&quot;: &quot;get_weather&quot;, &quot;arguments&quot;: { &quot;city&quot;: &quot;北京&quot; } }</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>应用调用天气 API，返回结果</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>模型: &quot;北京今天晴天，气温 25°C...&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="mcp-model-context-protocol" tabindex="-1">MCP（Model Context Protocol） <a class="header-anchor" href="#mcp-model-context-protocol" aria-label="Permalink to &quot;MCP（Model Context Protocol）&quot;">​</a></h3><p>Anthropic 提出的标准化协议，让 AI 模型能安全地访问外部工具和数据源：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AI 应用（Host）←→ MCP Client ←→ MCP Server ←→ 外部资源</span></span>
<span class="line"><span>                                    ↓</span></span>
<span class="line"><span>                      本地文件 / 数据库 / API / 浏览器</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>核心目标：</strong> 标准化工具接入方式，不再需要每个 AI 应用单独对接每个工具（类似 USB 协议之于外设）。</p><hr><h2 id="_5-用过哪些-ai-工具-用来做什么" tabindex="-1">5. 用过哪些 AI 工具 &amp; 用来做什么 <a class="header-anchor" href="#_5-用过哪些-ai-工具-用来做什么" aria-label="Permalink to &quot;5. 用过哪些 AI 工具 &amp; 用来做什么&quot;">​</a></h2><h3 id="日常开发" tabindex="-1">日常开发 <a class="header-anchor" href="#日常开发" aria-label="Permalink to &quot;日常开发&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">工具</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:left;">Claude / ChatGPT</td><td style="text-align:left;">代码生成、Bug 修复、代码 Review、技术问题解答</td></tr><tr><td style="text-align:left;">GitHub Copilot</td><td style="text-align:left;">IDE 内代码补全和生成</td></tr><tr><td style="text-align:left;">Claude Code</td><td style="text-align:left;">命令行 AI 编程助手，处理复杂重构和项目级任务</td></tr></tbody></table><h3 id="学习和准备面试" tabindex="-1">学习和准备面试 <a class="header-anchor" href="#学习和准备面试" aria-label="Permalink to &quot;学习和准备面试&quot;">​</a></h3><ul><li>让 AI 模拟面试官提问</li><li>总结和梳理技术知识点</li><li>分析简历和项目亮点</li></ul><hr><h2 id="_6-如何看待-deepseek" tabindex="-1">6. 如何看待 DeepSeek？ <a class="header-anchor" href="#_6-如何看待-deepseek" aria-label="Permalink to &quot;6. 如何看待 DeepSeek？&quot;">​</a></h2><p><strong>DeepSeek 的核心突破：</strong></p><ol><li><strong>低成本高性能</strong> — DeepSeek-V3 使用 MoE（Mixture of Experts）架构，在远低于 GPT-4 的训练成本下达到可比性能</li><li><strong>开源</strong> — 模型权重开源，极大降低了 AI 应用的门槛</li><li><strong>推理能力强</strong> — DeepSeek-R1 通过强化学习实现深度推理能力，展示了 &quot;思考过程&quot;（类似 o1）</li><li><strong>行业影响</strong> — 证明了 &quot;大力出奇迹&quot; 不是唯一路线，工程优化同样重要</li></ol><p><strong>面试中可以提到的观点：</strong></p><blockquote><p>&quot;DeepSeek 的出现对整个 AI 行业产生了深远影响。它证明了通过技术创新可以在较低成本下实现顶级性能，打破了 &#39;训练算力 = 模型能力&#39; 的固有认知。特别是 DeepSeek-R1 的推理能力，对需要复杂推理的企业应用场景（如代码审查、法律分析、医疗诊断）有很大价值。作为开发者，我更关注它开源带来的生态红利 — 可以在本地部署、微调，构建更可控的 AI 应用。&quot;</p></blockquote>`,45)])])}const g=t(l,[["render",i]]);export{h as __pageData,g as default};
